// src/pages/NotFoundPage/index.jsx

import React from 'react';
import s from './NotFoundPage.module.css';

// 🚀 Правильный относительный путь
import notFoundImage from '../../assets/images/404.png'; 

const NotFoundPage = () => {
  return (
    <div className={s.container}>
      <h1>404</h1>
      <p>Страница не найдена</p>
      {/* Обратите внимание: в React при использовании модульных бандлеров 
        (Webpack, Vite) картинка импортируется как переменная.
      */}
      <img 
        src={notFoundImage} 
        alt="Page not found" 
        className={s.image}
      />
    </div>
  );
};

export default NotFoundPage;
